import threading
import time
import uuid
from dataclasses import dataclass, field
from enum import Enum
from typing import Optional


class TransactionType(Enum):
    DEPOSIT = "deposit"
    WITHDRAWAL = "withdrawal"
    TRANSFER = "transfer"


class TransactionStatus(Enum):
    PENDING = "pending"
    COMPLETED = "completed"
    FAILED = "failed"
    ROLLED_BACK = "rolled_back"


@dataclass
class Transaction:
    transaction_id: str
    transaction_type: TransactionType
    amount: float
    source_account_id: Optional[str]
    destination_account_id: Optional[str]
    status: TransactionStatus = TransactionStatus.PENDING
    timestamp: float = field(default_factory=time.time)
    error_message: Optional[str] = None


class Account:
    def __init__(self, account_id: str, owner: str, initial_balance: float = 0.0):
        self.account_id = account_id
        self.owner = owner
        self._balance = initial_balance
        self._lock = threading.RLock()
        self._transaction_history: list[Transaction] = []

    @property
    def balance(self) -> float:
        with self._lock:
            return self._balance

    def _credit(self, amount: float) -> None:
        """Add funds to account. Must be called while holding the lock."""
        self._balance += amount

    def _debit(self, amount: float) -> None:
        """Remove funds from account. Must be called while holding the lock."""
        if self._balance < amount:
            raise InsufficientFundsError(
                f"Account {self.account_id} has insufficient funds. "
                f"Balance: {self._balance}, Requested: {amount}"
            )
        self._balance -= amount

    def add_transaction_record(self, transaction: Transaction) -> None:
        with self._lock:
            self._transaction_history.append(transaction)

    def get_transaction_history(self) -> list[Transaction]:
        with self._lock:
            return list(self._transaction_history)

    @property
    def lock(self) -> threading.RLock:
        return self._lock

    def __repr__(self) -> str:
        return f"Account(id={self.account_id}, owner={self.owner}, balance={self._balance})"


class InsufficientFundsError(Exception):
    pass


class AccountNotFoundError(Exception):
    pass


class InvalidTransactionError(Exception):
    pass


class TransactionProcessor:
    def __init__(self):
        self._accounts: dict[str, Account] = {}
        self._accounts_lock = threading.Lock()
        self._transaction_log: list[Transaction] = []
        self._log_lock = threading.Lock()

    def create_account(self, owner: str, initial_balance: float = 0.0) -> Account:
        if initial_balance < 0:
            raise InvalidTransactionError("Initial balance cannot be negative.")
        account_id = str(uuid.uuid4())
        account = Account(account_id, owner, initial_balance)
        with self._accounts_lock:
            self._accounts[account_id] = account
        return account

    def get_account(self, account_id: str) -> Account:
        with self._accounts_lock:
            account = self._accounts.get(account_id)
        if account is None:
            raise AccountNotFoundError(f"Account {account_id} not found.")
        return account

    def _log_transaction(self, transaction: Transaction) -> None:
        with self._log_lock:
            self._transaction_log.append(transaction)

    def get_transaction_log(self) -> list[Transaction]:
        with self._log_lock:
            return list(self._transaction_log)

    def deposit(self, account_id: str, amount: float) -> Transaction:
        if amount <= 0:
            raise InvalidTransactionError("Deposit amount must be positive.")

        account = self.get_account(account_id)
        transaction = Transaction(
            transaction_id=str(uuid.uuid4()),
            transaction_type=TransactionType.DEPOSIT,
            amount=amount,
            source_account_id=None,
            destination_account_id=account_id,
        )

        with account.lock:
            try:
                account._credit(amount)
                transaction.status = TransactionStatus.COMPLETED
            except Exception as e:
                transaction.status = TransactionStatus.FAILED
                transaction.error_message = str(e)

        account.add_transaction_record(transaction)
        self._log_transaction(transaction)
        return transaction

    def withdraw(self, account_id: str, amount: float) -> Transaction:
        if amount <= 0:
            raise InvalidTransactionError("Withdrawal amount must be positive.")

        account = self.get_account(account_id)
        transaction = Transaction(
            transaction_id=str(uuid.uuid4()),
            transaction_type=TransactionType.WITHDRAWAL,
            amount=amount,
            source_account_id=account_id,
            destination_account_id=None,
        )

        with account.lock:
            try:
                account._debit(amount)
                transaction.status = TransactionStatus.COMPLETED
            except InsufficientFundsError as e:
                transaction.status = TransactionStatus.FAILED
                transaction.error_message = str(e)
            except Exception as e:
                transaction.status = TransactionStatus.FAILED
                transaction.error_message = str(e)

        account.add_transaction_record(transaction)
        self._log_transaction(transaction)
        return transaction

    def transfer(self, source_account_id: str, destination_account_id: str, amount: float) -> Transaction:
        if amount <= 0:
            raise InvalidTransactionError("Transfer amount must be positive.")
        if source_account_id == destination_account_id:
            raise InvalidTransactionError("Cannot transfer to the same account.")

        source = self.get_account(source_account_id)
        destination = self.get_account(destination_account_id)

        transaction = Transaction(
            transaction_id=str(uuid.uuid4()),
            transaction_type=TransactionType.TRANSFER,
            amount=amount,
            source_account_id=source_account_id,
            destination_account_id=destination_account_id,
        )

        # Acquire locks in a consistent order (by account_id) to prevent deadlocks
        first, second = sorted([source, destination], key=lambda a: a.account_id)

        with first.lock:
            with second.lock:
                try:
                    source._debit(amount)
                    try:
                        destination._credit(amount)
                    except Exception as e:
                        # Roll back the debit if credit fails
                        source._credit(amount)
                        transaction.status = TransactionStatus.ROLLED_BACK
                        transaction.error_message = f"Credit failed, rolled back: {e}"
                        source.add_transaction_record(transaction)
                        destination.add_transaction_record(transaction)
                        self._log_transaction(transaction)
                        return transaction

                    transaction.status = TransactionStatus.COMPLETED
                except InsufficientFundsError as e:
                    transaction.status = TransactionStatus.FAILED
                    transaction.error_message = str(e)
                except Exception as e:
                    transaction.status = TransactionStatus.FAILED
                    transaction.error_message = str(e)

        source.add_transaction_record(transaction)
        destination.add_transaction_record(transaction)
        self._log_transaction(transaction)
        return transaction

    def process_batch(self, transactions: list[dict]) -> list[Transaction]:
        """
        Process a batch of transaction dictionaries.
        Each dict should have:
          - 'type': 'deposit', 'withdrawal', or 'transfer'
          - 'amount': float
          - 'account_id' (for deposit/withdrawal)
          - 'source_account_id' and 'destination_account_id' (for transfer)
        """
        results = []
        for txn_data in transactions:
            txn_type = txn_data.get("type")
            amount = txn_data.get("amount", 0)
            try:
                if txn_type == "deposit":
                    result = self.deposit(txn_data["account_id"], amount)
                elif txn_type == "withdrawal":
                    result = self.withdraw(txn_data["account_id"], amount)
                elif txn_type == "transfer":
                    result = self.transfer(
                        txn_data["source_account_id"],
                        txn_data["destination_account_id"],
                        amount,
                    )
                else:
                    raise InvalidTransactionError(f"Unknown transaction type: {txn_type}")
                results.append(result)
            except (InvalidTransactionError, AccountNotFoundError) as e:
                failed_txn = Transaction(
                    transaction_id=str(uuid.uuid4()),
                    transaction_type=TransactionType.DEPOSIT,  # placeholder
                    amount=amount,
                    source_account_id=txn_data.get("source_account_id"),
                    destination_account_id=txn_data.get("destination_account_id", txn_data.get("account_id")),
                    status=TransactionStatus.FAILED,
                    error_message=str(e),
                )
                results.append(failed_txn)
                self._log_transaction(failed_txn)
        return results


def run_concurrent_stress_test():
    """Demonstrate that the processor handles concurrent transactions safely."""
    processor = TransactionProcessor()

    # Create accounts
    alice = processor.create_account("Alice", 10000.0)
    bob = processor.create_account("Bob", 10000.0)
    charlie = processor.create_account("Charlie", 10000.0)

    print(f"Initial balances:")
    print(f"  Alice:   {alice.balance}")
    print(f"  Bob:     {bob.balance}")
    print(f"  Charlie: {charlie.balance}")
    initial_total = alice.balance + bob.balance + charlie.balance
    print(f"  Total:   {initial_total}")
    print()

    errors = []

    def worker_transfers(src_id, dst_id, count, amount):
        for _ in range(count):
            try:
                processor.transfer(src_id, dst_id, amount)
            except Exception as e:
                errors.append(e)

    def worker_deposits(account_id, count, amount):
        for _ in range(count):
            try:
                processor.deposit(account_id, amount)
            except Exception as e:
                errors.append(e)

    def worker_withdrawals(account_id, count, amount):
        for _ in range(count):
            try:
                processor.withdraw(account_id, amount)
            except Exception as e:
                errors.append(e)

    threads = [
        # Transfers between accounts
        threading.Thread(target=worker_transfers, args=(alice.account_id, bob.account_id, 100, 10.0)),
        threading.Thread(target=worker_transfers, args=(bob.account_id, alice.account_id, 100, 10.0)),
        threading.Thread(target=worker_transfers, args=(alice.account_id, charlie.account_id, 50, 5.0)),
        threading.Thread(target=worker_transfers, args=(charlie.account_id, bob.account_id, 50, 5.0)),
        threading.Thread(target=worker_transfers, args=(bob.account_id, charlie.account_id, 50, 5.0)),
        threading.Thread(target=worker_transfers, args=(charlie.account_id, alice.account_id, 50, 5.0)),
        # Deposits and withdrawals that should cancel out
        threading.Thread(target=worker_deposits, args=(alice.account_id, 100, 1.0)),
        threading.Thread(target=worker_withdrawals, args=(alice.account_id, 100, 1.0)),
        threading.Thread(target=worker_deposits, args=(bob.account_id, 100, 1.0)),
        threading.Thread(target=worker_withdrawals, args=(bob.account_id, 100, 1.0)),
    ]

    for t in threads:
        t.start()
    for t in threads:
        t.join()

    print(f"Final balances:")
    print(f"  Alice:   {alice.balance}")
    print(f"  Bob:     {bob.balance}")
    print(f"  Charlie: {charlie.balance}")
    final_total = alice.balance + bob.balance + charlie.balance
    print(f"  Total:   {final_total}")
    print()

    # Count completed and failed transactions
    log = processor.get_transaction_log()
    completed = sum(1 for t in log if t.status == TransactionStatus.COMPLETED)
    failed = sum(1 for t in log if t.status == TransactionStatus.FAILED)
    print(f"Transactions: {len(log)} total, {completed} completed, {failed} failed")

    if errors:
        print(f"Errors encountered: {len(errors)}")

    # Verify conservation of money: total should equal initial_total
    # (deposits and withdrawals cancel out, transfers conserve)
    assert abs(final_total - initial_total) < 0.001, (
        f"Money conservation violated! Expected {initial_total}, got {final_total}"
    )
    print("✓ Money conservation verified - no race conditions detected!")


def run_basic_demo():
    """Basic demonstration of the transaction processor."""
    processor = TransactionProcessor()

    # Create accounts
    alice = processor.create_account("Alice", 1000.0)
    bob = processor.create_account("Bob", 500.0)

    print("=== Basic Demo ===")
    print(f"Alice: {alice.balance}, Bob: {bob.balance}")

    # Deposit
    txn = processor.deposit(alice.account_id, 200.0)
    print(f"Deposit $200 to Alice: {txn.status.value} -> Alice: {alice.balance}")

    # Withdrawal
    txn = processor.withdraw(bob.account_id, 100.0)
    print(f"Withdraw $100 from Bob: {txn.status.value} -> Bob: {bob.balance}")

    # Transfer
    txn = processor.transfer(alice.account_id, bob.account_id, 300.0)
    print(f"Transfer $300 Alice->Bob: {txn.status.value} -> Alice: {alice.balance}, Bob: {bob.balance}")

    # Failed withdrawal (insufficient funds)
    txn = processor.withdraw(bob.account_id, 99999.0)
    print(f"Withdraw $99999 from Bob: {txn.status.value} ({txn.error_message})")

    # Batch processing
    print("\n--- Batch Processing ---")
    batch = [
        {"type": "deposit", "account_id": alice.account_id, "amount": 50.0},
        {"type": "withdrawal", "account_id": bob.account_id, "amount": 25.0},
        {"type": "transfer", "source_account_id": alice.account_id,
         "destination_account_id": bob.account_id, "amount": 100.0},
    ]
    results = processor.process_batch(batch)
    for r in results:
        print(f"  {r.transaction_type.value}: {r.status.value}")
    print(f"Final - Alice: {alice.balance}, Bob: {bob.balance}")
    print()


if __name__ == "__main__":
    run_basic_demo()
    print("=== Concurrent Stress Test ===")
    run_concurrent_stress_test()